INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'is', 54, 1, NULL, 'Adam Clarke em Is 54:1', 'Adam Clarke interpreta este versículo a partir de a exposição textual com aplicação pastoral objetiva. Em Isaías 54, Deus revela juízo, esperança e promessa messiânica de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Adam Clarke', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'is', 55, 1, NULL, 'João Calvino em Is 55:1', 'Segundo João Calvino, a centralidade das Escrituras e da graça soberana ilumina o sentido deste texto. Isaías 55 mostra que juízo, esperança e promessa messiânica sustenta a caminhada da fé, especialmente em adoração reverente. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'João Calvino', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'is', 56, 1, NULL, 'John Brown of Haddington em Is 56:1', 'Na leitura de John Brown of Haddington, vemos a piedade prática e a santificação do coração. Isaías 56 evidencia juízo, esperança e promessa messiânica como eixo da vida do povo de Deus, com ênfase em amor fraternal. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'John Brown of Haddington', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'is', 57, 1, NULL, 'Albert Barnes em Is 57:1', 'Segundo Albert Barnes, a exposição textual com aplicação pastoral objetiva ilumina o sentido deste texto. Isaías 57 mostra que juízo, esperança e promessa messiânica sustenta a caminhada da fé, especialmente em arrependimento sincero. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Albert Barnes', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'is', 58, 1, NULL, 'Martinho Lutero em Is 58:1', 'Martinho Lutero destaca a centralidade das Escrituras e da graça soberana. Em Isaías 58, o foco recai sobre juízo, esperança e promessa messiânica e chama a igreja para vida de oração. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Martinho Lutero', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'is', 59, 1, NULL, 'Thomas Boston em Is 59:1', 'Thomas Boston interpreta este versículo a partir de a piedade prática e a santificação do coração. Em Isaías 59, Deus revela juízo, esperança e promessa messiânica de forma pastoral e transformadora, promovendo santidade prática. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Thomas Boston', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'is', 60, 1, NULL, 'Herman Bavinck em Is 60:1', 'Herman Bavinck destaca a coerência doutrinária aplicada à vida cristã. Em Isaías 60, o foco recai sobre juízo, esperança e promessa messiânica e chama a igreja para justiça com misericórdia. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Herman Bavinck', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'is', 61, 1, NULL, 'Bernardo de Claraval em Is 61:1', 'Na leitura de Bernardo de Claraval, vemos a síntese entre fé, razão e vida santa. Isaías 61 evidencia juízo, esperança e promessa messiânica como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Bernardo de Claraval', 'commentary', '#6B4F2A', NOW()),
